-- ============================================================
-- Hub Master - Schema Unificado (Todos os bancos)
-- Adiciona tabelas de subscriptions e favorites ao PostgreSQL
-- ============================================================

-- ============================================================
-- Tabela: subscriptions (migrado do SQLite do subscription-api)
-- ============================================================
CREATE TABLE IF NOT EXISTS subscriptions (
    id TEXT PRIMARY KEY,
    name TEXT NOT NULL,
    price REAL NOT NULL,
    currency TEXT DEFAULT 'BRL',
    billing_cycle TEXT DEFAULT 'monthly',
    renewal_date TEXT NOT NULL,
    category TEXT DEFAULT 'other',
    color TEXT DEFAULT '#6366f1',
    icon TEXT DEFAULT '',
    is_active BOOLEAN DEFAULT true,
    notes TEXT DEFAULT '',
    created_at TEXT DEFAULT CURRENT_TIMESTAMP,
    updated_at TEXT DEFAULT CURRENT_TIMESTAMP
);

-- ============================================================
-- Tabela: favorites (migrado do arquivo txt do favoritos)
-- ============================================================
CREATE TABLE IF NOT EXISTS favorites (
    id SERIAL PRIMARY KEY,
    name TEXT NOT NULL,
    url TEXT NOT NULL,
    created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_favorites_name ON favorites(name);
CREATE INDEX IF NOT EXISTS idx_favorites_url ON favorites(url);

